```cpp
#include <iostream>
using namespace std;

class Shape {
public:
    virtual void draw() {
        cout << "Drawing Shape" << endl;
    }
    virtual ~Shape() {} // virtual destructor
};

class Circle : public Shape {
public:
    void draw() override {
        cout << "Drawing Circle" << endl;
    }
};

class Rectangle : public Shape {
public:
    void draw() override {
        cout << "Drawing Rectangle" << endl;
    }
};

int main() {
    Shape* shapes[2];
    shapes[0] = new Circle();
    shapes[1] = new Rectangle();
    for (int i = 0; i < 2; i++) {
        shapes[i]->draw(); // calls derived class version
        delete shapes[i];
    }
    return 0;
}
```
Output: 'Drawing Circle' then 'Drawing Rectangle'. Virtual functions enable dynamic dispatch via vtable. The base class pointer calls the correct derived method at runtime.

